// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

// Імпортуємо попередні реєстри кандидатів та виборців
import "./CandidateRegistry.sol";
import "./VoterRegistry.sol";

// Керуючий контракт успадковує логіку обох реєстрів
contract Vote is CandidateRegistry, VoterRegistry {
    
    // 1. Еnum для опису етапів (станів) голосування
    enum Status {
        NotStarted, // Голосування ще не почалося (йде реєстрація)
        Active,     // Голосування активне (можна голосувати)
        Finished    // Голосування завершено
    }

    // 2. Змінна стану голосування
    Status public status;

    // 3. Події для логування життєвого циклу голосування
    event VotingStarted();
    event VoteCast(address indexed voter, uint indexed candidateId);
    event VotingFinished();

    // 4. Модифікатор, який дозволяє голосувати ТІЛЬКИ коли статус Active
    modifier onlyDuringVoting() {
        require(status == Status.Active, "Voting is not active");
        _;
    }

    // 5. Функція додавання кандидатів власником (тільки ДО початку голосування)
    function addCandidateToVote(string memory name) external onlyOwner {
        require(status == Status.NotStarted, "Cannot add candidates after start");
        addCandidate(name); // Викликаємо внутрішню функцію з CandidateRegistry
    }

    // Функція реєстрації виборців власником (тільки ДО початку голосування)
    function registerVoterToVote(address voterAddress) external onlyOwner {
        require(status == Status.NotStarted, "Cannot register voters after start");
        _registerVoter(voterAddress); // Викликаємо внутрішню функцію з VoterRegistry
    }

    // 6. Функція запуску голосування власником
    function startVoting() external onlyOwner {
        require(status == Status.NotStarted, "Voting already started or finished");
        status = Status.Active;
        emit VotingStarted();
    }

    // 7. Функція завершення голосування власником
    function finishVoting() external onlyOwner onlyDuringVoting {
        status = Status.Finished;
        emit VotingFinished();
    }

    // 8. Публічна функція для голосування користувачами
    function vote(uint candidateId) external onlyDuringVoting {
        // Отримуємо посилання на структуру виборця у пам'яті storage для її зміни
        Voter storage senderVoter = voters[msg.sender];

        // Перевірка А: Чи зареєстрований цей акаунт власником проекту
        require(senderVoter.isRegistered, "You are not registered to vote");
        
        // Перевірка Б: Чи не голосував цей користувач раніше
        require(!senderVoter.hasVoted, "You have already voted");

        // Логіка зміни стану:
        senderVoter.hasVoted = true;      // Позначаємо, що користувач проголосував
        voteCandidate(candidateId);        // Зараховуємо голос кандидату через CandidateRegistry

        // Генеруємо подію успішного голосування
        emit VoteCast(msg.sender, candidateId);
    }
}

contracts/CandidateRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.28;

import "./Ownable.sol";

abstract contract CandidateRegistry is Ownable {
    // 1. Структура кандидата
    struct Candidate {
        uint id;
        string name;
        uint votes;
    }

    // 2. Динамічний масив для зберігання всіх кандидатів
    Candidate[] public candidates;

    // 3. Подія, яка викликається при додаванні нового кандидата
    event CandidateAdded(uint id, string name);

    // 4. Внутрішня (internal) функція для додавання кандидата
    // Вона доступна тільки всередині цього контракту та його нащадків
    function addCandidate(string memory name) internal {
        uint newId = candidates.length; // ID дорівнює поточному індексу в масиві

        // Створюємо та додаємо нового кандидата (початкові голоси = 0)
        candidates.push(Candidate(newId, name, 0));

        // Генеруємо подію додавання
        emit CandidateAdded(newId, name);
    }

    // 5. Внутрішня функція для збільшення кількості голосів кандидата
    function voteCandidate(uint id) internal {
        // Перевіряємо, що такий кандидат взагалі існує в масиві
        require(id < candidates.length, "Candidate does not exist");
        candidates[id].votes++;
    }

    // 6. Публічна функція для отримання інформації про кандидата за його ID
    function getCandidate(uint id) external view returns (uint, string memory, uint) {
        require(id < candidates.length, "Candidate does not exist");
        Candidate memory c = candidates[id];
        return (c.id, c.name, c.votes);
    }

    // 7. Публічна функція, що повертає загальну кількість кандидатів
    function totalCandidates() external view returns (uint) {
        return candidates.length;
    }
}

